var surah038 = {
  number: 38,
  nameArabic: "Sad",
  nameEnglish: "Sad",
  meaning: "Sad",
  totalAyahs: 88,
  ayahs: [
    { number: 1, arabic: "صٓ ۚ وَٱلْقُرْءَانِ ذِى ٱلذِّكْرِ", transliteration: "Sad waalqurani thee alththikri", transliterationB: "Saaad; wal-Qur-aani ziz zikr", english: "Sad: By the Qur'an, Full of Admonition: (This is the Truth)", romanUrdu: "Saad, kasam hai naseehat bharey Quran ki" },
    { number: 2, arabic: "بَلِ ٱلَّذِينَ كَفَرُوا۟ فِى عِزَّةٍۢ وَشِقَاقٍۢ", transliteration: "Bali allatheena kafaroo fee AAizzatin washiqaqin", transliterationB: "Balil lazeena kafaroo fee 'izzatilnw wa shiqaaq", english: "But the Unbelievers (are steeped) in self-glory and Separatism", romanUrdu: "Balke yahi log, jinhon ne maanney se inkar kiya hai, sakht takabbur aur zid mein mubtila hain" },
    { number: 3, arabic: "كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّن قَرْنٍۢ فَنَادَوا۟ وَّلَاتَ حِينَ مَنَاصٍۢ", transliteration: "Kam ahlakna min qablihim min qarnin fanadaw walata heena manasin", transliterationB: "Kam ahlaknaa min qablihim min qarnin fanaadaw wa laata heena manaas", english: "How many generations before them did We destroy? In the end they cried (for mercy)- when there was no longer time for being saved", romanUrdu: "Insey pehle hum aisi kitni hi qaumon ko halaak kar chuke hain (aur jab unki shamat aayi hai) to woh cheekh utthey hain, magar woh waqt bachne ka nahin hota" },
    { number: 4, arabic: "وَعَجِبُوٓا۟ أَن جَآءَهُم مُّنذِرٌۭ مِّنْهُمْ ۖ وَقَالَ ٱلْكَٰفِرُونَ هَٰذَا سَٰحِرٌۭ كَذَّابٌ", transliteration: "WaAAajiboo an jaahum munthirun minhum waqala alkafiroona hatha sahirun kaththabun", transliterationB: "Wa 'ajibooo an jaaa'a hum munzirum minhum wa qaalal kaafiroona haazaa saahirun kazzaab", english: "So they wonder that a Warner has come to them from among themselves! and the Unbelievers say, \"This is a sorcerer telling lies", romanUrdu: "In logon ko is baat par bada taajub hua ke ek darane wala khud inhi mein se aa gaya, munkireen kehne lagey ke “yeh saahir(sorcerer) hai, sakht jhoota hai" },
    { number: 5, arabic: "أَجَعَلَ ٱلْءَالِهَةَ إِلَٰهًۭا وَٰحِدًا ۖ إِنَّ هَٰذَا لَشَىْءٌ عُجَابٌۭ", transliteration: "AjaAAala alalihata ilahan wahidan inna hatha lashayon AAujabun", transliterationB: "Aja'alal aalihata Ilaahanw Waahidan inna haazaa lashai'un 'ujaab", english: "Has he made the gods (all) into one Allah? Truly this is a wonderful thing", romanUrdu: "Kya isney saarey khudaon ki jagah bas ek hi khuda bana dala? Yeh to badi ajeeb baat hai”" },
    { number: 6, arabic: "وَٱنطَلَقَ ٱلْمَلَأُ مِنْهُمْ أَنِ ٱمْشُوا۟ وَٱصْبِرُوا۟ عَلَىٰٓ ءَالِهَتِكُمْ ۖ إِنَّ هَٰذَا لَشَىْءٌۭ يُرَادُ", transliteration: "Waintalaqa almalao minhum ani imshoo waisbiroo AAala alihatikum inna hatha lashayon yuradu", transliterationB: "Wantalaqal mala-u minhum anim shoo wasbiroo 'alaaa aalihatikum innna haazaa lashai 'uny yuraad", english: "And the leader among them go away (impatiently), (saying), \"Walk ye away, and remain constant to your gods! For this is truly a thing designed (against you)", romanUrdu: "Aur sardaran e qaum yeh kehte huey nikal gaye ke “ chalo aur dat-tey raho apne maboodon ki ibadat par. Yeh baat to kisi aur hi garaz se kahi ja rahi hai" },
    { number: 7, arabic: "مَا سَمِعْنَا بِهَٰذَا فِى ٱلْمِلَّةِ ٱلْءَاخِرَةِ إِنْ هَٰذَآ إِلَّا ٱخْتِلَٰقٌ", transliteration: "Ma samiAAna bihatha fee almillati alakhirati in hatha illa ikhtilaqun", transliterationB: "Maa sami'naa bihaazaa fil millatil aakhirati in haazaaa illakh tilaaq", english: "We never heard (the like) of this among the people of these latter days: this is nothing but a made-up tale", romanUrdu: "Yeh baat humne zamana e qareeb ki millat mein kisi se nahin suni. Yeh kuch nahin hai magar ek man-ghadat baat" },
    { number: 8, arabic: "أَءُنزِلَ عَلَيْهِ ٱلذِّكْرُ مِنۢ بَيْنِنَا ۚ بَلْ هُمْ فِى شَكٍّۢ مِّن ذِكْرِى ۖ بَل لَّمَّا يَذُوقُوا۟ عَذَابِ", transliteration: "Aonzila AAalayhi alththikru min baynina bal hum fee shakkin min thikree bal lamma yathooqoo AAathabi", transliterationB: "A-unzila 'alaihiz zikru mim baininaa; bal hum fee shakkim min Zikree bal lammaa yazooqoo 'azaab", english: "What! has the Message been sent to him - (Of all persons) among us?\"... but they are in doubt concerning My (Own) Message! Nay, they have not yet tasted My Punishment", romanUrdu: "Kya hamarey darmiyan bas yahi ek shaks reh gaya tha jispar Allah ka zikr nazil kardiya gaya?”Asal baat yeh hai ke yeh mere “Zikr” par shakk kar rahey hain , aur yeh saari baatein isliye kar rahey hain ke inhon ne mere azaab ka maza chakkha nahin hai" },
    { number: 9, arabic: "أَمْ عِندَهُمْ خَزَآئِنُ رَحْمَةِ رَبِّكَ ٱلْعَزِيزِ ٱلْوَهَّابِ", transliteration: "Am AAindahum khazainu rahmati rabbika alAAazeezi alwahhabi", transliterationB: "Am'indahum khazaaa 'inu rahmati Rabbikal 'Azeezil Wahhab", english: "Or have they the treasures of the mercy of thy Lord,- the Exalted in Power, the Grantor of Bounties without measure", romanUrdu: "Kya tere daata (great Bestower) aur gaalib parwardigar ki rehmat ke khazane inke kabze mein hain" },
    { number: 10, arabic: "أَمْ لَهُم مُّلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ۖ فَلْيَرْتَقُوا۟ فِى ٱلْأَسْبَٰبِ", transliteration: "Am lahum mulku alssamawati waalardi wama baynahuma falyartaqoo fee alasbabi", transliterationB: "Am lahum mulkus samaawaati wal ardi wa maa bainahumaa falyartaqoo fil asbaab", english: "Or have they the dominion of the heavens and the earth and all between? If so, let them mount up with the ropes and means (to reach that end)", romanUrdu: "Kya yeh aasmaan o zameen aur inke darmiyan ki cheezon ke maalik hain? Accha to yeh aalam e asbaab ki bulandiyon par chadh kar dekhein" },
    { number: 11, arabic: "جُندٌۭ مَّا هُنَالِكَ مَهْزُومٌۭ مِّنَ ٱلْأَحْزَابِ", transliteration: "Jundun ma hunalika mahzoomun mina alahzabi", transliterationB: "Jundum maa hunaalika mahzoomum minal Ahzaab", english: "But there - will be put to flight even a host of confederates", romanUrdu: "Yeh to jatthon (armies) mein se ek choota sa jattha (army) hai jo isi jagah shikhast(suffer defeat) khane wala hai" },
    { number: 12, arabic: "كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ وَعَادٌۭ وَفِرْعَوْنُ ذُو ٱلْأَوْتَادِ", transliteration: "Kaththabat qablahum qawmu noohin waAAadun wafirAAawnu thoo alawtadi", transliterationB: "Kazzabat qablahum qawmu Lootinw-wa 'Aadunw wa Fir'awnu zul awtaad", english: "Before them (were many who) rejected messengers,- the people of Noah, and 'Ad, and Pharaoh, the Lord of Stakes", romanUrdu: "Insey pehle Nooh ki qaum, aur Aad, aur mekhon (tent-pegs/stakes) wala Firoun" },
    { number: 13, arabic: "وَثَمُودُ وَقَوْمُ لُوطٍۢ وَأَصْحَٰبُ لْـَٔيْكَةِ ۚ أُو۟لَٰٓئِكَ ٱلْأَحْزَابُ", transliteration: "Wathamoodu waqawmu lootin waashabu alaykati olaika alahzabu", transliterationB: "Wa Samoodu wa qawmu Lootinw wa Ashaabul 'Aykah; ulaaa'ikal Ahzaab", english: "And Thamud, and the people of Lut, and the Companions of the Wood; - such were the Confederates", romanUrdu: "Aur Samood, aur qaum e Lut, aur aika waley jhutla chuke hain. Jatthay woh thay" },
    { number: 14, arabic: "إِن كُلٌّ إِلَّا كَذَّبَ ٱلرُّسُلَ فَحَقَّ عِقَابِ", transliteration: "In kullun illa kaththaba alrrusula fahaqqa AAiqabi", transliterationB: "In kullun illaa kazzabar Rusula fahaqqa 'iqaab", english: "Not one (of them) but rejected the messengers, but My punishment came justly and inevitably (on them)", romanUrdu: "Unmein se har ek ne Rasoolon ko jhutlaya aur meri uqubat ka faisla (decree of chastisement )uspar chaspan ho kar raha" },
    { number: 15, arabic: "وَمَا يَنظُرُ هَٰٓؤُلَآءِ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ مَّا لَهَا مِن فَوَاقٍۢ", transliteration: "Wama yanthuru haolai illa sayhatan wahidatan ma laha min fawaqin", transliterationB: "Wa maa yanzuru haaa ulaaa'i illaa saihatanw waahidatam maa lahaa min fawaaq", english: "These (today) only wait for a single mighty Blast, which (when it comes) will brook no delay", romanUrdu: "Yeh log bhi bas ek dhamake ke muntazir hain jiske baad koi dusra dhamaka na hoga" },
    { number: 16, arabic: "وَقَالُوا۟ رَبَّنَا عَجِّل لَّنَا قِطَّنَا قَبْلَ يَوْمِ ٱلْحِسَابِ", transliteration: "Waqaloo rabbana AAajjil lana qittana qabla yawmi alhisabi", transliterationB: "Wa qaaloo Rabbanaa 'ajjil lanaa qittanaa qabla Yawmil Hisaab", english: "They say: \"Our Lord! hasten to us our sentence (even) before the Day of Account", romanUrdu: "Aur yeh kehte hain ke aey hamare Rubb, yaum ul hisaab(hisab ke din) se pehle hi hamara hissa humein jaldi se dey dey" },
    { number: 17, arabic: "ٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَٱذْكُرْ عَبْدَنَا دَاوُۥدَ ذَا ٱلْأَيْدِ ۖ إِنَّهُۥٓ أَوَّابٌ", transliteration: "Isbir AAala ma yaqooloona waothkur AAabdana dawooda tha alaydi innahu awwabun", transliterationB: "Isbir 'alaa maa yaqooloona wazkur 'abdanaa Daawooda zal aidi aidi innahooo awwaab", english: "Have patience at what they say, and remember our servant David, the man of strength: for he ever turned (to Allah)", romanUrdu: "(Aey Nabi), sabr karo un baaton par jo yeh log banate hain, aur inke saamne hamare banday Dawood ka qissa bayan karo jo badi quwaton ka maalik tha. Har maamle mein Allah ki taraf rujoo karne wala tha" },
    { number: 18, arabic: "إِنَّا سَخَّرْنَا ٱلْجِبَالَ مَعَهُۥ يُسَبِّحْنَ بِٱلْعَشِىِّ وَٱلْإِشْرَاقِ", transliteration: "Inna sakhkharna aljibala maAAahu yusabbihna bialAAashiyyi waalishraqi", transliterationB: "Innaa sakhkharnal jibaala ma'ahoo yusabbihna bil'ashaiyi wal ishraaq", english: "It was We that made the hills declare, in unison with him, Our Praises, at eventide and at break of day", romanUrdu: "Humne pahadon ko uske saath musakkhar kar rakkha tha ke subah o shaam woh uske saath tasbeeh karte thay" },
    { number: 19, arabic: "وَٱلطَّيْرَ مَحْشُورَةًۭ ۖ كُلٌّۭ لَّهُۥٓ أَوَّابٌۭ", transliteration: "Waalttayra mahshooratan kullun lahu awwabun", transliterationB: "Wattayra mahshoorah; kullul lahooo awwaab", english: "And the birds gathered (in assemblies): all with him did turn (to Allah)", romanUrdu: "Parindey simat aate aur sabke sab uski tasbeeh ki taraf mutawajjeh ho jatey thay" },
    { number: 20, arabic: "وَشَدَدْنَا مُلْكَهُۥ وَءَاتَيْنَٰهُ ٱلْحِكْمَةَ وَفَصْلَ ٱلْخِطَابِ", transliteration: "Washadadna mulkahu waataynahu alhikmata wafasla alkhitabi", transliterationB: "Wa shadadnaa mulkahoo wa aatainaahul Hikmata wa faslal khitaab", english: "We strengthened his kingdom, and gave him wisdom and sound judgment in speech and decision", romanUrdu: "Humne uski sultanat mazboot kardi thi, usko hikmat ata ki thi aur faislay-kun baat kehne ki salahiyat bakshi thi" },
    { number: 21, arabic: "۞ وَهَلْ أَتَىٰكَ نَبَؤُا۟ ٱلْخَصْمِ إِذْ تَسَوَّرُوا۟ ٱلْمِحْرَابَ", transliteration: "Wahal ataka nabao alkhasmi ith tasawwaroo almihraba", transliterationB: "Wa hal ataaka naba'ul khasm; iz tasawwarul mihraab", english: "Has the Story of the Disputants reached thee? Behold, they climbed over the wall of the private chamber", romanUrdu: "Phir tumhein kuch khabar pahunchi hai un muqaddame walon ki jo deewaar chadh kar uske baala khaane(private chambers) mein ghus aaye thay" },
    { number: 22, arabic: "إِذْ دَخَلُوا۟ عَلَىٰ دَاوُۥدَ فَفَزِعَ مِنْهُمْ ۖ قَالُوا۟ لَا تَخَفْ ۖ خَصْمَانِ بَغَىٰ بَعْضُنَا عَلَىٰ بَعْضٍۢ فَٱحْكُم بَيْنَنَا بِٱلْحَقِّ وَلَا تُشْطِطْ وَٱهْدِنَآ إِلَىٰ سَوَآءِ ٱلصِّرَٰطِ", transliteration: "Ith dakhaloo AAala dawooda fafaziAAa minhum qaloo la takhaf khasmani bagha baAAduna AAala baAAdin faohkum baynana bialhaqqi wala tushtit waihdina ila sawai alssirati", transliterationB: "Iz dakhaloo 'alaa Daawooda fafazi'a minhum qaaloo la takhaf khasmaani baghaa ba'dunaa 'alaa ba'din fahkum bainanaaa bilhaqqi wa laa tushtit wahdinaaa ilaa Sawaaa'is Siraat", english: "When they entered the presence of David, and he was terrified of them, they said: \"Fear not: we are two disputants, one of whom has wronged the other: Decide now between us with truth, and treat us not with injustice, but guide us to the even Path", romanUrdu: "Jab woh Dawood ke paas pahunche to woh unhein dekh kar ghabra gaya, unhon ne kaha “dariye nahin, hum do fareeq muqaddama hain jin mein se ek ne dusre par zyadati ki hai. Aap hamare darmiyan theek theek haqq ke saath faisla kardijiye, be-insafi na kijiye aur humein raah e raast bataiye" },
    { number: 23, arabic: "إِنَّ هَٰذَآ أَخِى لَهُۥ تِسْعٌۭ وَتِسْعُونَ نَعْجَةًۭ وَلِىَ نَعْجَةٌۭ وَٰحِدَةٌۭ فَقَالَ أَكْفِلْنِيهَا وَعَزَّنِى فِى ٱلْخِطَابِ", transliteration: "Inna hatha akhee lahu tisAAun watisAAoona naAAjatan waliya naAAjatun wahidatun faqala akfilneeha waAAazzanee fee alkhitabi", transliterationB: "Inna haazaaa akhee lahoo tis'unw wa tis'oona na'jatanw wa liya na'jatunw waahidah; faqaala akfilneeha wa 'azzanee filkhitaab", english: "This man is my brother: He has nine and ninety ewes, and I have (but) one: Yet he says, 'commit her to my care,' and is (moreover) harsh to me in speech", romanUrdu: "Yeh meri bhai hai ,iske paas ninanve (ninety nine) dumbiyan(ewes) hai aur mere paas sirf ek hi dumbi (ewe) hai , isne mujhse kaha ke yeh ek dumbi bhi mere hawale karde aur isne guftagu mein mujhe daba liya”" },
    { number: 24, arabic: "قَالَ لَقَدْ ظَلَمَكَ بِسُؤَالِ نَعْجَتِكَ إِلَىٰ نِعَاجِهِۦ ۖ وَإِنَّ كَثِيرًۭا مِّنَ ٱلْخُلَطَآءِ لَيَبْغِى بَعْضُهُمْ عَلَىٰ بَعْضٍ إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَقَلِيلٌۭ مَّا هُمْ ۗ وَظَنَّ دَاوُۥدُ أَنَّمَا فَتَنَّٰهُ فَٱسْتَغْفَرَ رَبَّهُۥ وَخَرَّ رَاكِعًۭا وَأَنَابَ ۩", transliteration: "Qala laqad thalamaka bisuali naAAjatika ila niAAajihi wainna katheeran mina alkhulatai layabghee baAAduhum AAala baAAdin illa allatheena amanoo waAAamiloo alssalihati waqaleelun ma hum wathanna dawoodu annama fatannahu faistaghfara rabbahu wakharra rakiAAan waanaba", transliterationB: "Qaala laqad zalamaka bisu 'aali na'jatika ilaa ni'aajihee wa inna kaseeram minal khulataaa'i la-yabghee ba'duhum 'alaa ba'din illal lazeena aamanoo wa 'amilus saalihaati wa qaleehum maa hum; wa zanna Daawoodu annamaa fatannaahu fastaghrara Rabbahoo wa kharra raaki'anw wa anaab", english: "(David) said: \"He has undoubtedly wronged thee in demanding thy (single) ewe to be added to his (flock of) ewes: truly many are the partners (in business) who wrong each other: Not so do those who believe and work deeds of righteousness, and how few are they?\"... and David gathered that We had tried him: he asked forgiveness of his Lord, fell down, bowing (in prostration), and turned (to Allah in repentance)", romanUrdu: "Dawood ne jawab diya: “is shaks ne apni dumbiyon (ewes) ke saath teri dumbi mila lene ka mutalaba karke yaqeenan tujhpar zulm kiya, aur waqiya yeh hai ke mil-jhul kar saath rehne waley log aksar ek dusre par zyadatiyan karte rehte hain, bas wahi log is se bachey huey hain jo iman rakhte hain aur amal e saleh karte hain, aur aisey log kam hi hain.” (Yeh baat kehte kehte) Dawood samajh gaya ke yeh to humne dar-asal iski aazmaish ki hai, chunanche usne apne Rubb se maafi maangi aur sajde mein gir gaya aur rujoo karliya" },
    { number: 25, arabic: "فَغَفَرْنَا لَهُۥ ذَٰلِكَ ۖ وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍۢ", transliteration: "Faghafarna lahu thalika wainna lahu AAindana lazulfa wahusna maabin", transliterationB: "Faghafarnaa lahoo zaalik; wa inna lahoo 'indanaa lazulfaa wa husna ma aab", english: "So We forgave him this (lapse): he enjoyed, indeed, a Near Approach to Us, and a beautiful place of (Final) Return", romanUrdu: "Tab humne iska woh kasoor maaf kiya aur yaqeenan hamare haan uske liye taqarrub ka muqaam aur behtar anjaam hai" },
    { number: 26, arabic: "يَٰدَاوُۥدُ إِنَّا جَعَلْنَٰكَ خَلِيفَةًۭ فِى ٱلْأَرْضِ فَٱحْكُم بَيْنَ ٱلنَّاسِ بِٱلْحَقِّ وَلَا تَتَّبِعِ ٱلْهَوَىٰ فَيُضِلَّكَ عَن سَبِيلِ ٱللَّهِ ۚ إِنَّ ٱلَّذِينَ يَضِلُّونَ عَن سَبِيلِ ٱللَّهِ لَهُمْ عَذَابٌۭ شَدِيدٌۢ بِمَا نَسُوا۟ يَوْمَ ٱلْحِسَابِ", transliteration: "Ya dawoodu inna jaAAalnaka khaleefatan fee alardi faohkum bayna alnnasi bialhaqqi wala tattabiAAi alhawa fayudillaka AAan sabeeli Allahi inna allatheena yadilloona AAan sabeeli Allahi lahum AAathabun shadeedun bima nasoo yawma alhisabi", transliterationB: "Yaa Daawoodu innaa ja'alnaaka khaleefatan fil ardi fahkum bainan naasi bilhaqqi wa laa tattabi'il hawaa fayudillaka 'an sabeelil laah; innal lazeena yadilloona 'an sabeelil laah; lahum 'azaabun shadeedum bimaa nasoo Yawmal Hisaab", english: "O David! We did indeed make thee a vicegerent on earth: so judge thou between men in truth (and justice): Nor follow thou the lusts (of thy heart), for they will mislead thee from the Path of Allah: for those who wander astray from the Path of Allah, is a Penalty Grievous, for that they forget the Day of Account", romanUrdu: "(Humne ussey kaha) “Aey dawood, humne tujhey zameen mein khalifa banaya hai, lihaza tu logon ke darmiyan haqq ke saath hukumat kar, aur khwaish e nafs ki pairwi na kar ke woh tujhey Allah ki raah se bhatka degi. Jo log Allah ki raah se bhatakte hain yaqeenan unke liye sakht saza hai ke woh yaum ul hisaab ko bhool gaye.”" },
    { number: 27, arabic: "وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا بَٰطِلًۭا ۚ ذَٰلِكَ ظَنُّ ٱلَّذِينَ كَفَرُوا۟ ۚ فَوَيْلٌۭ لِّلَّذِينَ كَفَرُوا۟ مِنَ ٱلنَّارِ", transliteration: "Wama khalaqna alssamaa waalarda wama baynahuma batilan thalika thannu allatheena kafaroo fawaylun lillatheena kafaroo mina alnnari", transliterationB: "Wa ma khalaqnas samaaa'a wal arda wa maa bainahumaa baatilaa; zaalika zannul lazeena kafaroo; fawi lul lillazeena kafaroo minan Naar", english: "Not without purpose did We create heaven and earth and all between! that were the thought of Unbelievers! but woe to the Unbelievers because of the Fire (of Hell)", romanUrdu: "Humne is aasmaan aur zameen ko, aur is duniya ko jo inke darmiyan hai , fizool paida nahin kardiya hai, yeh to un logon ka gumaan hai jinhon ne kufr kiya hai aur aisey kaafiron ke liye barbadi hai jahannum ki aag se" },
    { number: 28, arabic: "أَمْ نَجْعَلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ كَٱلْمُفْسِدِينَ فِى ٱلْأَرْضِ أَمْ نَجْعَلُ ٱلْمُتَّقِينَ كَٱلْفُجَّارِ", transliteration: "Am najAAalu allatheena amanoo waAAamiloo alssalihati kaalmufsideena fee alardi am najAAalu almuttaqeena kaalfujjari", transliterationB: "Am naj'alul lazeena aamanoo wa 'amilus saalihaati kalmufisdeena fil ardi am naj'alul muttaqeena kalfujjaar", english: "Shall We treat those who believe and work deeds of righteousness, the same as those who do mischief on earth? Shall We treat those who guard against evil, the same as those who turn aside from the right", romanUrdu: "Kya hum un logon ko jo iman laatey hain aur neik aamaal karte hain aur unko jo zameen mein fasad karne waley hain yaksan kardein? Kya muttaqiyon ko hum faajiron(wicked) jaisa kardein" },
    { number: 29, arabic: "كِتَٰبٌ أَنزَلْنَٰهُ إِلَيْكَ مُبَٰرَكٌۭ لِّيَدَّبَّرُوٓا۟ ءَايَٰتِهِۦ وَلِيَتَذَكَّرَ أُو۟لُوا۟ ٱلْأَلْبَٰبِ", transliteration: "Kitabun anzalnahu ilayka mubarakun liyaddabbaroo ayatihi waliyatathakkara oloo alalbabi", transliterationB: "Kitaabun anzalnaahu ilaika mubaarakul liyaddabbarooo Aayaatihee wa liyatazakkara ulul albaab", english: "(Here is) a Book which We have sent down unto thee, full of blessings, that they may mediate on its Signs, and that men of understanding may receive admonition", romanUrdu: "Yeh ek badi barakat wali kitaab hai jo (aey Muhammad) humne tumhari taraf nazil ki hai taa-ke yeh log iski aayat par gaur karein aur aqal o fikr rakhne wale issey sabaq lein" },
    { number: 30, arabic: "وَوَهَبْنَا لِدَاوُۥدَ سُلَيْمَٰنَ ۚ نِعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌ", transliteration: "Wawahabna lidawooda sulaymana niAAma alAAabdu innahu awwabun", transliterationB: "Wa wahabnaa li Daawooda Sulaimaan; ni'mal 'abd; innahoo awwaab", english: "To David We gave Solomon (for a son),- How excellent in Our service! Ever did he turn (to Us)", romanUrdu: "Aur Dawood ko humne Sulaiman (jaisa beta) ata kiya, behtareen banda, kasrat se apne Rubb ki taraf rujoo karne wala" },
    { number: 31, arabic: "إِذْ عُرِضَ عَلَيْهِ بِٱلْعَشِىِّ ٱلصَّٰفِنَٰتُ ٱلْجِيَادُ", transliteration: "Ith AAurida AAalayhi bialAAashiyyi alssafinatu aljiyadu", transliterationB: "Iz 'urida 'alaihi bil'ashiy yis saafinaatul jiyaad", english: "Behold, there were brought before him, at eventide coursers of the highest breeding, and swift of foot", romanUrdu: "Kaabil e zikr hai woh mauqa jab shaam ke waqt us ke saamne khoob sidhey (well-trained) huey tez-rau(running) ghoday (horses) pesh kiye gaye" },
    { number: 32, arabic: "فَقَالَ إِنِّىٓ أَحْبَبْتُ حُبَّ ٱلْخَيْرِ عَن ذِكْرِ رَبِّى حَتَّىٰ تَوَارَتْ بِٱلْحِجَابِ", transliteration: "Faqala innee ahbabtu hubba alkhayri AAan thikri rabbee hatta tawarat bialhijabi", transliterationB: "Faqaala inneee ahbabtu hubbal khairi 'an zikri Rabbee hattaa tawaarat bilhijaab", english: "And he said, \"Truly do I love the love of good, with a view to the glory of my Lord,\"- until (the sun) was hidden in the veil (of night)", romanUrdu: "To usne kaha “maine is maal ki muhabbat apne Rubb ki yaad ki wajah se ikhtiyar ki hai” yahan tak ke jab woh ghoday (horses) nigaah se ojhal ho gaye" },
    { number: 33, arabic: "رُدُّوهَا عَلَىَّ ۖ فَطَفِقَ مَسْحًۢا بِٱلسُّوقِ وَٱلْأَعْنَاقِ", transliteration: "Ruddooha AAalayya fatafiqa mashan bialssooqi waalaAAnaqi", transliterationB: "Ruddoohaa 'alaiya fatafiqa masham bissooqi wal a'naaq", english: "Bring them back to me.\" then began he to pass his hand over (their) legs and their necks", romanUrdu: "To (usne hukum diya ke) inhein mere paas wapas laao, phir laga unki pindliyon (legs) aur gardano (necks) par haath pherne" },
    { number: 34, arabic: "وَلَقَدْ فَتَنَّا سُلَيْمَٰنَ وَأَلْقَيْنَا عَلَىٰ كُرْسِيِّهِۦ جَسَدًۭا ثُمَّ أَنَابَ", transliteration: "Walaqad fatanna sulaymana waalqayna AAala kursiyyihi jasadan thumma anaba", transliterationB: "Wa laqad fatannaa Sulaimaana wa alqainaa 'alaa kursiyyihee jasadan summa anaab", english: "And We did try Solomon: We placed on his throne a body (without life); but he did turn (to Us in true devotion)", romanUrdu: "Aur (dekho ke) Sulaiman ko bhi humne aazmaish mein daala aur uski kursi par ek jasad (mere body/body without life) laa kar daal diya phir usne rujoo kiya" },
    { number: 35, arabic: "قَالَ رَبِّ ٱغْفِرْ لِى وَهَبْ لِى مُلْكًۭا لَّا يَنۢبَغِى لِأَحَدٍۢ مِّنۢ بَعْدِىٓ ۖ إِنَّكَ أَنتَ ٱلْوَهَّابُ", transliteration: "Qala rabbi ighfir lee wahab lee mulkan la yanbaghee liahadin min baAAdee innaka anta alwahhabu", transliterationB: "Qaala Rabbigh fir lee wa hab lee mulkal laa yambaghee li ahadim mim ba'de inaka Antal Wahhab", english: "He said, \"O my Lord! Forgive me, and grant me a kingdom which, (it may be), suits not another after me: for Thou art the Grantor of Bounties (without measure)", romanUrdu: "Aur kaha ke “aey mere Rubb , mujhey maaf karde aur mujhey woh baadshahi de jo mere baad kisi ke liye sazawar na ho, beshak tu hi asal daata hai”" },
    { number: 36, arabic: "فَسَخَّرْنَا لَهُ ٱلرِّيحَ تَجْرِى بِأَمْرِهِۦ رُخَآءً حَيْثُ أَصَابَ", transliteration: "Fasakhkharna lahu alrreeha tajree biamrihi rukhaan haythu asaba", transliterationB: "Fasakhkharnaa lahur reeha tajree bi amrihee rukhaaa'an haisu asaab", english: "Then We subjected the wind to his power, to flow gently to his order, Whithersoever he willed", romanUrdu: "Tab humne uske liye hawa ko musakkhar kardiya jo uske hukum se narmi ke saath chalti thi jidhar woh chahta tha" },
    { number: 37, arabic: "وَٱلشَّيَٰطِينَ كُلَّ بَنَّآءٍۢ وَغَوَّاصٍۢ", transliteration: "Waalshshayateena kulla bannain waghawwasin", transliterationB: "Wash Shayaateena kulla bannaaa'inw wa ghawwaas", english: "As also the evil ones, (including) every kind of builder and diver", romanUrdu: "Aur shayateen ko musakkhar kardiya, har tarah ke meimaar(builders) aur gotakhor (divers)" },
    { number: 38, arabic: "وَءَاخَرِينَ مُقَرَّنِينَ فِى ٱلْأَصْفَادِ", transliteration: "Waakhareena muqarraneena fee alasfadi", transliterationB: "Wa aakhareena muqarraneena fil asfaad", english: "As also others bound together in fetters", romanUrdu: "Aur dusre jo paband e salasil thay(bound with chains)" },
    { number: 39, arabic: "هَٰذَا عَطَآؤُنَا فَٱمْنُنْ أَوْ أَمْسِكْ بِغَيْرِ حِسَابٍۢ", transliteration: "Hatha AAataona faomnun aw amsik bighayri hisabin", transliterationB: "Haazaa 'ataaa'unaa famnun aw amsik bighairi hisaab", english: "Such are Our Bounties: whether thou bestow them (on others) or withhold them, no account will be asked", romanUrdu: "(humne ussey kaha) “ yeh hamari bakshish hai, tujhey ikhtiyar hai jisey chahe de aur jissey chahe rok le, koi hisaab nahin”" },
    { number: 40, arabic: "وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍۢ", transliteration: "Wainna lahu AAindana lazulfa wahusna maabin", transliterationB: "Wa inna lahoo 'indanaa lazulfaa wa husna ma-aab", english: "And he enjoyed, indeed, a Near Approach to Us, and a beautiful Place of (Final) Return", romanUrdu: "Yaqeenan uske liye hamare haan taqarrub ka muqaam aur behtar anjaam hai" },
    { number: 41, arabic: "وَٱذْكُرْ عَبْدَنَآ أَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلشَّيْطَٰنُ بِنُصْبٍۢ وَعَذَابٍ", transliteration: "Waothkur AAabdana ayyooba ith nada rabbahu annee massaniya alshshaytanu binusbin waAAathabin", transliterationB: "Wazkur 'abdanaaa Ayyoob; iz naada Rabbahooo annee massaniyash Shaitaanu binus binw wa 'azaab", english: "Commemorate Our Servant Job. Behold he cried to his Lord: \"The Evil One has afflicted me with distress and suffering", romanUrdu: "Aur hamare banday Ayub ka zikar karo, jab usne apne Rubb ko pukara ke shaytaan ne mujhey sakht takleef aur azaab mein daal diya hai" },
    { number: 42, arabic: "ٱرْكُضْ بِرِجْلِكَ ۖ هَٰذَا مُغْتَسَلٌۢ بَارِدٌۭ وَشَرَابٌۭ", transliteration: "Orkud birijlika hatha mughtasalun baridun washarabun", transliterationB: "Urkud birijlika haaza mughtasalum baaridunw wa sharaab", english: "(The command was given:) \"Strike with thy foot: here is (water) wherein to wash, cool and refreshing, and (water) to drink", romanUrdu: "(Humne usey hukum diya) apna paaon (leg) zameen par maar, yeh hai thanda pani nahane ke liya aur peene ke liye" },
    { number: 43, arabic: "وَوَهَبْنَا لَهُۥٓ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةًۭ مِّنَّا وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَٰبِ", transliteration: "Wawahabna lahu ahlahu wamithlahum maAAahum rahmatan minna wathikra liolee alalbabi", transliterationB: "Wa wahabnaa lahoo ahlahoo wa mislahum ma'ahum rahmatam minna wa zikraa li ulil albaab", english: "And We gave him (back) his people, and doubled their number,- as a Grace from Ourselves, and a thing for commemoration, for all who have Understanding", romanUrdu: "Humne usey uske ahal o ayaal wapas diye aur unke saath utnay hi aur, apni taraf se rehmat ke taur par, aur aqal o fikar rakhne walon ke liye dars ke taur par" },
    { number: 44, arabic: "وَخُذْ بِيَدِكَ ضِغْثًۭا فَٱضْرِب بِّهِۦ وَلَا تَحْنَثْ ۗ إِنَّا وَجَدْنَٰهُ صَابِرًۭا ۚ نِّعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌۭ", transliteration: "Wakhuth biyadika dighthan faidrib bihi wala tahnath inna wajadnahu sabiran niAAma alAAabdu innahu awwabun", transliterationB: "Wa khuz biyadika dighsan fadrib bihee wa laa tahnas, innaa wajadnaahu saabiraa; ni'mal 'abd; innahooo awwaab", english: "And take in thy hand a little grass, and strike therewith: and break not (thy oath).\" Truly We found him full of patience and constancy. How excellent in Our service! ever did he turn (to Us)", romanUrdu: "(Aur humne issey kaha) tinkon ka ek mutta lay (bundle of rushes) aur ussey maar de, apni kasam na todh, humne usey saabir paya, behtareen banda, apne Rubb ki taraf bahut rujoo karne wala" },
    { number: 45, arabic: "وَٱذْكُرْ عِبَٰدَنَآ إِبْرَٰهِيمَ وَإِسْحَٰقَ وَيَعْقُوبَ أُو۟لِى ٱلْأَيْدِى وَٱلْأَبْصَٰرِ", transliteration: "Waothkur AAibadana ibraheema waishaqa wayaAAqooba olee alaydee waalabsari", transliterationB: "Wazkur 'ibaadanaaa Ibraaheema wa Is-haaqa wa Ya'qooba ulil-aydee walabsaar", english: "And commemorate Our Servants Abraham, Isaac, and Jacob, possessors of Power and Vision", romanUrdu: "Aur hamare bandon , Ibrahim aur Ishaq aur Yaqub ka zikar karo badi quwwat e amail rakhne wale aur deedhawar (strength and vision)log thay" },
    { number: 46, arabic: "إِنَّآ أَخْلَصْنَٰهُم بِخَالِصَةٍۢ ذِكْرَى ٱلدَّارِ", transliteration: "Inna akhlasnahum bikhalisatin thikra alddari", transliterationB: "Innaaa akhlasnaahum bi khaalisatin zikrad daar", english: "Verily We did choose them for a special (purpose)- proclaiming the Message of the Hereafter", romanUrdu: "Humne unko ek khaalis siffat ki bina par barguzida kiya tha, aur woh daar-e-aakhirat ki yaad thi" },
    { number: 47, arabic: "وَإِنَّهُمْ عِندَنَا لَمِنَ ٱلْمُصْطَفَيْنَ ٱلْأَخْيَارِ", transliteration: "Wainnahum AAindana lamina almustafayna alakhyari", transliterationB: "Wa innahum 'indanaa laminal mustafainal akhyaar", english: "They were, in Our sight, truly, of the company of the Elect and the Good", romanUrdu: "Yaqeenan hamare haan unka shumaar chunay huey neik ashkhaas(excellent ones) mein hai" },
    { number: 48, arabic: "وَٱذْكُرْ إِسْمَٰعِيلَ وَٱلْيَسَعَ وَذَا ٱلْكِفْلِ ۖ وَكُلٌّۭ مِّنَ ٱلْأَخْيَارِ", transliteration: "Waothkur ismaAAeela wailyasaAAa watha alkifli wakullun mina alakhyari", transliterationB: "Wazkur Ismaa'eela wal Yasa'a wa Zal-Kifli wa kullum minal akhyaar", english: "And commemorate Isma'il, Elisha, and Zul-Kifl: Each of them was of the Company of the Good", romanUrdu: "Aur Ismail aur Al-yasa(Elisha) aur Zulkifl ka zikr karo, yeh sab neik logon mein se thay" },
    { number: 49, arabic: "هَٰذَا ذِكْرٌۭ ۚ وَإِنَّ لِلْمُتَّقِينَ لَحُسْنَ مَـَٔابٍۢ", transliteration: "Hatha thikrun wainna lilmuttaqeena lahusna maabin", transliterationB: "Haazaa zikr; wa inna lilmuttaqeena lahusna ma aab", english: "This is a Message (of admonition): and verily, for the righteous, is a beautiful Place of (Final) Return", romanUrdu: "Yeh ek zikar tha. (Ab suno ke) muttaqi logon ke liye yaqeenan behtareen thikana hai" },
    { number: 50, arabic: "جَنَّٰتِ عَدْنٍۢ مُّفَتَّحَةًۭ لَّهُمُ ٱلْأَبْوَٰبُ", transliteration: "Jannati AAadnin mufattahatan lahumu alabwabu", transliterationB: "Jannaati 'adnim mufat tahatal lahumul abwaab", english: "Gardens of Eternity, whose doors will (ever) be open to them", romanUrdu: "Hamesha rehne wali jannatein jinke darwaze unke liye khuley hongey" },
    { number: 51, arabic: "مُتَّكِـِٔينَ فِيهَا يَدْعُونَ فِيهَا بِفَٰكِهَةٍۢ كَثِيرَةٍۢ وَشَرَابٍۢ", transliteration: "Muttakieena feeha yadAAoona feeha bifakihatin katheeratin washarabin", transliterationB: "Muttaki'eena feehaa yad'oona feehaa bifaakihatin kaseeratinw wa sharaab", english: "Therein will they recline (at ease): Therein can they call (at pleasure) for fruit in abundance, and (delicious) drink", romanUrdu: "Unmein woh takiye lagaye baithay hongey, khoob khoob fawake aur mashroobat (abundant fruit and drinks) talab kar rahey hongey" },
    { number: 52, arabic: "۞ وَعِندَهُمْ قَٰصِرَٰتُ ٱلطَّرْفِ أَتْرَابٌ", transliteration: "WaAAindahum qasiratu alttarfi atrabun", transliterationB: "Wa 'indahum qaasiraatut tarfi atraab", english: "And beside them will be chaste women restraining their glances, (companions) of equal age", romanUrdu: "Aur unke paas sharmili humsin biwiyan hongi" },
    { number: 53, arabic: "هَٰذَا مَا تُوعَدُونَ لِيَوْمِ ٱلْحِسَابِ", transliteration: "Hatha ma tooAAadoona liyawmi alhisabi", transliterationB: "Haaza maa too'odoona li Yawmil Hisaab", english: "Such is the Promise made, to you for the Day of Account", romanUrdu: "Yeh woh chezein hain jinhein hisaab ke din ata karne ka tumse wada kiya ja raha hai" },
    { number: 54, arabic: "إِنَّ هَٰذَا لَرِزْقُنَا مَا لَهُۥ مِن نَّفَادٍ", transliteration: "Inna hatha larizquna ma lahu min nafadin", transliterationB: "Inna haazaa larizqunaa maa lahoo min nafaad", english: "Truly such will be Our Bounty (to you); it will never fail", romanUrdu: "Yeh hamara rizq hai jo kabhi khatam honaywala nahin" },
    { number: 55, arabic: "هَٰذَا ۚ وَإِنَّ لِلطَّٰغِينَ لَشَرَّ مَـَٔابٍۢ", transliteration: "Hatha wainna lilttagheena lasharra maabin", transliterationB: "Haazaa; wa inna littaagheena lasharra ma-aab", english: "Yea, such! but - for the wrong-doers will be an evil place of (Final) Return", romanUrdu: "Yeh to hai muttaqiyon ka anjaam aur sarkashon ke liye badhtareen (evil) thikana hai" },
    { number: 56, arabic: "جَهَنَّمَ يَصْلَوْنَهَا فَبِئْسَ ٱلْمِهَادُ", transliteration: "Jahannama yaslawnaha fabisa almihadu", transliterationB: "Jahannama yaslawnahaa fai'sal mihaad", english: "Hell!- they will burn therein, - an evil bed (indeed, to lie on)", romanUrdu: "Jahannum jismein woh jhulse jayenge. Bahut hi buri qayamgaah" },
    { number: 57, arabic: "هَٰذَا فَلْيَذُوقُوهُ حَمِيمٌۭ وَغَسَّاقٌۭ", transliteration: "Hatha falyathooqoohu hameemun waghassaqun", transliterationB: "Haazaa falyazooqoohu hameemunw wa ghassaaq", english: "Yea, such! - then shall they taste it,- a boiling fluid, and a fluid dark, murky, intensely cold", romanUrdu: "Yeh hai unke liye, pas woh maza chakhein khautley (boiling) huey pani aur peep lahu (pus)" },
    { number: 58, arabic: "وَءَاخَرُ مِن شَكْلِهِۦٓ أَزْوَٰجٌ", transliteration: "Waakharu min shaklihi azwajun", transliterationB: "Wa aakharu min shak liheee azwaaj", english: "And other Penalties of a similar kind, to match them", romanUrdu: "Aur isi qisam ki dusri talkhiyon ka" },
    { number: 59, arabic: "هَٰذَا فَوْجٌۭ مُّقْتَحِمٌۭ مَّعَكُمْ ۖ لَا مَرْحَبًۢا بِهِمْ ۚ إِنَّهُمْ صَالُوا۟ ٱلنَّارِ", transliteration: "Hatha fawjun muqtahimun maAAakum la marhaban bihim innahum saloo alnnari", transliterationB: "Haazaa fawjum muqtahimum ma'akum laa marhabam bihim; innahum saalun Naar", english: "Here is a troop rushing headlong with you! No welcome for them! truly, they shall burn in the Fire", romanUrdu: "(woh jahannum ki taraf apne pairawon ko aatey dekh kar aapas mein kahenge) “Yeh ek lashkar tumhare paas ghusa chala aa raha hai, koi khushamadeed (welcome) inke liye nahin hai, yeh aag mein jhulasne waley hain”" },
    { number: 60, arabic: "قَالُوا۟ بَلْ أَنتُمْ لَا مَرْحَبًۢا بِكُمْ ۖ أَنتُمْ قَدَّمْتُمُوهُ لَنَا ۖ فَبِئْسَ ٱلْقَرَارُ", transliteration: "Qaloo bal antum la marhaban bikum antum qaddamtumoohu lana fabisa alqararu", transliterationB: "Qaaloo bal antum laa marhabam bikum; antum qaddamtumoohu lanaa fabi'sal qaraar", english: "(The followers shall cry to the misleaders:) \"Nay, ye (too)! No welcome for you! It is ye who have brought this upon us! Now evil is (this) place to stay in", romanUrdu: "Woh unko jawab denge “ nahin balke tum hi jhulse ja rahe ho, koi khair maqdam tumhare liye nahin. Tumhi to yeh anjaam hamare aagey laye ho. Kaisi buri hai yeh jaaye qaraar”" },
    { number: 61, arabic: "قَالُوا۟ رَبَّنَا مَن قَدَّمَ لَنَا هَٰذَا فَزِدْهُ عَذَابًۭا ضِعْفًۭا فِى ٱلنَّارِ", transliteration: "Qaloo rabbana man qaddama lana hatha fazidhu AAathaban diAAfan fee alnnari", transliterationB: "Qaaloo Rabbanaa man qaddama lanaa haaza fazidhu 'azaaban di'fan fin Naar", english: "They will say: \"Our Lord! whoever brought this upon us,- Add to him a double Penalty in the Fire", romanUrdu: "Phir woh kahenge “Aey hamare Rubb, jisne humein is anjaam ko pahunchane ka bandobast kiya usko dozakh ka dohra azaab de”" },
    { number: 62, arabic: "وَقَالُوا۟ مَا لَنَا لَا نَرَىٰ رِجَالًۭا كُنَّا نَعُدُّهُم مِّنَ ٱلْأَشْرَارِ", transliteration: "Waqaloo ma lana la nara rijalan kunna naAAudduhum mina alashrari", transliterationB: "Wa qaaloo ma lanaa laa naraa rijaalan kunnaa na'udduhum minal ashraar", english: "And they will say: \"What has happened to us that we see not men whom we used to number among the bad ones", romanUrdu: "Aur woh aapas mein kahenge “kya baat hai, hum un logon ko kahin nahin dekhte jinehin hum duniya mein bura samajte thay" },
    { number: 63, arabic: "أَتَّخَذْنَٰهُمْ سِخْرِيًّا أَمْ زَاغَتْ عَنْهُمُ ٱلْأَبْصَٰرُ", transliteration: "Attakhathnahum sikhriyyan am zaghat AAanhumu alabsaru", transliterationB: "Attakhaznaahum sikh riyyan am zaaghat 'anhumul absaar", english: "Did we treat them (as such) in ridicule, or have (our) eyes failed to perceive them", romanUrdu: "Hunme yunhi unka mazaaq bana liya tha, ya woh kahin nazaron se ojhal hain?”" },
    { number: 64, arabic: "إِنَّ ذَٰلِكَ لَحَقٌّۭ تَخَاصُمُ أَهْلِ ٱلنَّارِ", transliteration: "Inna thalika lahaqqun takhasumu ahli alnnari", transliterationB: "Inna zaalika lahaqqun takhaasumu Ahlin Naar", english: "Truly that is just and fitting,- the mutual recriminations of the People of the Fire", romanUrdu: "Beshak yeh baat sacchi hai, ehle dozakh mein yahi kuch jhagde honay waley hain" },
    { number: 65, arabic: "قُلْ إِنَّمَآ أَنَا۠ مُنذِرٌۭ ۖ وَمَا مِنْ إِلَٰهٍ إِلَّا ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ", transliteration: "Qul innama ana munthirun wama min ilahin illa Allahu alwahidu alqahharu", transliterationB: "Qul innamaaa ana munzirunw wa maa min ilaahim illal laahul Waahidul Qahhaar", english: "Say: \"Truly am I a Warner: no god is there but the one Allah, Supreme and Irresistible", romanUrdu: "(Aey Nabi) insey kaho, “ main to bas khabardar kardene wala hoon. Koi haqeeqi mabood nahin magar Allah, jo yakta hai, sab par gaalib" },
    { number: 66, arabic: "رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ٱلْعَزِيزُ ٱلْغَفَّٰرُ", transliteration: "Rabbu alssamawati waalardi wama baynahuma alAAazeezu alghaffaru", transliterationB: "Rabbus samaawaati wal ardi wa maa bainahumal 'Azeezul Ghaffaar", english: "The Lord of the heavens and the earth, and all between,- Exalted in Might, able to enforce His Will, forgiving again and again", romanUrdu: "Aasmaano aur zameen ka maalik aur un saari cheezon ka maalik jo inke darmiyan hain, zabardast aur darguzar karne wala”" },
    { number: 67, arabic: "قُلْ هُوَ نَبَؤٌا۟ عَظِيمٌ", transliteration: "Qul huwa nabaon AAatheemun", transliterationB: "Qul huwa naba'un 'azeem", english: "Say: \"That is a Message Supreme (above all)", romanUrdu: "Insey kaho “ yeh ek badi khabar hai" },
    { number: 68, arabic: "أَنتُمْ عَنْهُ مُعْرِضُونَ", transliteration: "Antum AAanhu muAAridoona", transliterationB: "Antum 'anhu mu'ridoon", english: "From which ye do turn away", romanUrdu: "Jisko sunkar tum mooh pherte ho”" },
    { number: 69, arabic: "مَا كَانَ لِىَ مِنْ عِلْمٍۭ بِٱلْمَلَإِ ٱلْأَعْلَىٰٓ إِذْ يَخْتَصِمُونَ", transliteration: "Ma kana liya min AAilmin bialmalai alaAAla ith yakhtasimoona", transliterationB: "Maa kaana liya min 'ilmim bilmala il a'laaa iz yakhtasimoon", english: "No knowledge have I of the Chiefs on high, when they discuss (matters) among themselves", romanUrdu: "(Insey kaho) “Mujhey us waqt ki koi khabar na thi jab mala-e-aala (high council) mein jhagda ho raha tha" },
    { number: 70, arabic: "إِن يُوحَىٰٓ إِلَىَّ إِلَّآ أَنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌ", transliteration: "In yooha ilayya illa annama ana natheerun mubeenun", transliterationB: "Iny-yoohaaa ilaiya illaaa annnamaaa ana nazeerum mubeen", english: "Only this has been revealed to me: that I am to give warning plainly and publicly", romanUrdu: "Mujhko to wahee (revelation/inspiration) ke zariye se yeh baatein sirf isliye batayi jaati hain ke main khula khula khabardar karne wala hoon”" },
    { number: 71, arabic: "إِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى خَٰلِقٌۢ بَشَرًۭا مِّن طِينٍۢ", transliteration: "Ith qala rabbuka lilmalaikati innee khaliqun basharan min teenin", transliterationB: "Iz qaala Rabbuka lilmalaaa'ikati innee khaaliqum basharam min teen", english: "Behold, thy Lord said to the angels: \"I am about to create man from clay", romanUrdu: "Jab tere Rubb ne farishton se kaha “main mitti se ek bashar banane wala hoon" },
    { number: 72, arabic: "فَإِذَا سَوَّيْتُهُۥ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُوا۟ لَهُۥ سَٰجِدِينَ", transliteration: "Faitha sawwaytuhu wanafakhtu feehi min roohee faqaAAoo lahu sajideena", transliterationB: "Fa-iza sawwaituhoo wa nafakhtu feehi mir roohee faqa'oo lahoo saajideen", english: "When I have fashioned him (in due proportion) and breathed into him of My spirit, fall ye down in obeisance unto him", romanUrdu: "Phir jab main usey puri tarah bana doon aur usmein apni rooh phoonk doon to tum uske aagey sajde mein gir jao”" },
    { number: 73, arabic: "فَسَجَدَ ٱلْمَلَٰٓئِكَةُ كُلُّهُمْ أَجْمَعُونَ", transliteration: "Fasajada almalaikatu kulluhum ajmaAAoona", transliterationB: "Fasajadal malaaa'ikatu kulluhum ajma'oon", english: "So the angels prostrated themselves, all of them together", romanUrdu: "Is hukum ke mutaabiq farishtey sab ke sab sajde mein gir gaye" },
    { number: 74, arabic: "إِلَّآ إِبْلِيسَ ٱسْتَكْبَرَ وَكَانَ مِنَ ٱلْكَٰفِرِينَ", transliteration: "Illa ibleesa istakbara wakana mina alkafireena", transliterationB: "Illaaa Iblees; istakbara wa kaana minal kaafireen", english: "Not so Iblis: he was haughty, and became one of those who reject Faith", romanUrdu: "Magar Iblis ne apni badayi ka ghamand kiya aur woh kaafiron mein se ho gaya" },
    { number: 75, arabic: "قَالَ يَٰٓإِبْلِيسُ مَا مَنَعَكَ أَن تَسْجُدَ لِمَا خَلَقْتُ بِيَدَىَّ ۖ أَسْتَكْبَرْتَ أَمْ كُنتَ مِنَ ٱلْعَالِينَ", transliteration: "Qala ya ibleesu ma manaAAaka an tasjuda lima khalaqtu biyadayya astakbarta am kunta mina alAAaleena", transliterationB: "Qaala yaaa Ibleesu maa man'aka an tasjuda limaa khalaqtu biyadai; astakbarta am kunta min 'aaleen", english: "(Allah) said: \"O Iblis! What prevents thee from prostrating thyself to one whom I have created with my hands? Art thou haughty? Or art thou one of the high (and mighty) ones", romanUrdu: "Rubb ne farmaya “Aey Iblis, tujhey kya cheez usko sajda karne se maanay hui jisey maine apne dono haathon se banaya hai? Tu bada ban raha hai ya tu hai hi kuch unchey darje ki hastiyon mein se?”" },
    { number: 76, arabic: "قَالَ أَنَا۠ خَيْرٌۭ مِّنْهُ ۖ خَلَقْتَنِى مِن نَّارٍۢ وَخَلَقْتَهُۥ مِن طِينٍۢ", transliteration: "Qala ana khayrun minhu khalaqtanee min narin wakhalaqtahu min teenin", transliterationB: "Qaala ana khairum minah; khalaqtanee min naarinw wa khalaqtahoo min teen", english: "(Iblis) said: \"I am better than he: thou createdst me from fire, and him thou createdst from clay", romanUrdu: "Usne jawab diya “main ussey behtar hoon , aapne mujhko aag se paida kiya hai aur isko mitti se”" },
    { number: 77, arabic: "قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌۭ", transliteration: "Qala faokhruj minha fainnaka rajeemun", transliterationB: "Qaala fakhruj minhaa fainnaka rajeem", english: "(Allah) said: \"Then get thee out from here: for thou art rejected, accursed", romanUrdu: "Farmaya “ accha to yahan se nikal ja , tu mardood hai" },
    { number: 78, arabic: "وَإِنَّ عَلَيْكَ لَعْنَتِىٓ إِلَىٰ يَوْمِ ٱلدِّينِ", transliteration: "Wainna AAalayka laAAnatee ila yawmi alddeeni", transliterationB: "Wa inna 'alaika la'nateee ilaa Yawmid Deen", english: "And My curse shall be on thee till the Day of Judgment", romanUrdu: "Aur tere upar yaum ul jaza tak meri laanat hai”" },
    { number: 79, arabic: "قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ", transliteration: "Qala rabbi faanthirnee ila yawmi yubAAathoona", transliterationB: "Qaala Rabbi fa anzirneee ilaa Yawmi yub'asoon", english: "(Iblis) said: \"O my Lord! Give me then respite till the Day the (dead) are raised", romanUrdu: "Woh bola “ aey mere Rubb , yeh baat hai to phir mujhey us waqt tak ke liye mohlat dey dey jab yeh log dobara uthaye jayenge”" },
    { number: 80, arabic: "قَالَ فَإِنَّكَ مِنَ ٱلْمُنظَرِينَ", transliteration: "Qala fainnaka mina almunthareena", transliterationB: "Qaala fa innaka minal munzareen", english: "(Allah) said: \"Respite then is granted thee", romanUrdu: "Farmaya, “accha tujhey us roz tak ki mohlat hai" },
    { number: 81, arabic: "إِلَىٰ يَوْمِ ٱلْوَقْتِ ٱلْمَعْلُومِ", transliteration: "Ila yawmi alwaqti almaAAloomi", transliterationB: "Ilaa Yawmil waqtil ma'loom", english: "Till the Day of the Time Appointed", romanUrdu: "Jiska waqt mujhey maloom hai”" },
    { number: 82, arabic: "قَالَ فَبِعِزَّتِكَ لَأُغْوِيَنَّهُمْ أَجْمَعِينَ", transliteration: "Qala fabiAAizzatika laoghwiyannahum ajmaAAeena", transliterationB: "Qaala fabi'izzatika la ughwiyannahum ajma'een", english: "(Iblis) said: \"Then, by Thy power, I will put them all in the wrong", romanUrdu: "Usne kaha “ teri izzat ki kasam, main in sab logon ko behka kar rahunga" },
    { number: 83, arabic: "إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ", transliteration: "Illa AAibadaka minhumu almukhlaseena", transliterationB: "Illaa 'ibaadaka minhumul mukhlaseen", english: "Except Thy Servants amongst them, sincere and purified (by Thy Grace)", romanUrdu: "Bajuz tere un bandon ke jinhein tu nay khaalis karliya hai”" },
    { number: 84, arabic: "قَالَ فَٱلْحَقُّ وَٱلْحَقَّ أَقُولُ", transliteration: "Qala faalhaqqu waalhaqqa aqoolu", transliterationB: "Qaala falhaqq, walhaqqa aqool", english: "(Allah) said: \"Then it is just and fitting- and I say what is just and fitting", romanUrdu: "Farmaya “to haqq yeh hai, aur main haqq hi kaha karta hoon" },
    { number: 85, arabic: "لَأَمْلَأَنَّ جَهَنَّمَ مِنكَ وَمِمَّن تَبِعَكَ مِنْهُمْ أَجْمَعِينَ", transliteration: "Laamlaanna jahannama minka wamimman tabiAAaka minhum ajmaAAeena", transliterationB: "La amla'annna Jahannama minka wa mimman tabi'aka minhum ajma'een", english: "That I will certainly fill Hell with thee and those that follow thee,- every one", romanUrdu: "Ke main jahannum ko tujhse aur un sab logon se bhar dunga jo in Insano mein se teri pairwi karenge”" },
    { number: 86, arabic: "قُلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍۢ وَمَآ أَنَا۠ مِنَ ٱلْمُتَكَلِّفِينَ", transliteration: "Qul ma asalukum AAalayhi min ajrin wama ana mina almutakallifeena", transliterationB: "Qul maaa as'alukum 'alaihi min ajrinw wa maaa ana minal mutakallifeen", english: "Say: \"No reward do I ask of you for this (Qur'an), nor am I a pretender", romanUrdu: "(Aey Nabi) insey kehdo ke main is tableeg par tumse koi ajar nahin maangta, aur na main banawati logon mein se hoon" },
    { number: 87, arabic: "إِنْ هُوَ إِلَّا ذِكْرٌۭ لِّلْعَٰلَمِينَ", transliteration: "In huwa illa thikrun lilAAalameena", transliterationB: "In huwa illaa zikrul lil'aalameen", english: "This is no less than a Message to (all) the Worlds", romanUrdu: "Yeh to ek naseehat hai tamam jahaan walon ke liye" },
    { number: 88, arabic: "وَلَتَعْلَمُنَّ نَبَأَهُۥ بَعْدَ حِينٍۭ", transliteration: "WalataAAlamunna nabaahu baAAda heenin", transliterationB: "Wa lata'lamunna naba ahoo ba'da heen", english: "And ye shall certainly know the truth of it (all) after a while", romanUrdu: "Aur thodi muddat hi guzaregi ke tumhein iska haal khud maaloom ho jayega" }
  ]
};
